INSERT INTO blog_posts (
title, slug, content, excerpt, featured_image_url, status, user_id,
is_featured, view_count, like_count, comment_count,
scheduled_at, published_at, created_at, updated_at
) VALUES (
#{title}, #{slug}, #{content}, #{excerpt}, #{featuredImage}, #{status}, #{authorId},
#{isFeatured, jdbcType=BOOLEAN},
#{viewCount}, #{likeCount}, #{commentCount},
#{scheduledAt}, #{publishedAt}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT bp.id, bp.title, bp.slug, bp.excerpt, bp.featured_image_url, bp.status, bp.view_count, bp.like_count, bp.comment_count, bp.published_at, bp.created_at, bp.updated_at, u.full_name AS author_name, u.profile_picture_url AS author_avatar, STRING_AGG(DISTINCT bc.name, ', ') AS categories, STRING_AGG(DISTINCT bt.name, ', ') AS tags FROM blog_posts bp LEFT JOIN users u ON bp.user_id = u.id LEFT JOIN blog_post_categories bpc ON bp.id = bpc.blog_post_id LEFT JOIN blog_categories bc ON bpc.category_id = bc.id LEFT JOIN blog_post_tags bpt ON bp.id = bpt.blog_post_id LEFT JOIN blog_tags bt ON bpt.tag_id = bt.id
bp.status = #{status} bp.status = 'PUBLISHED'
AND bc.slug = #{category} AND bt.slug = #{tag}
AND (bp.title ILIKE '%' || #{search} || '%' OR bp.content ILIKE '%' || #{search} || '%' OR bp.excerpt ILIKE '%' || #{search} || '%')
AND bp.user_id = #{authorId}
GROUP BY bp.id, u.full_name, u.profile_picture_url ORDER BY
bp.title bp.view_count bp.like_count bp.comment_count bp.updated_at bp.created_at
${sortType} LIMIT #{limit} OFFSET #{offset}

SELECT bp.id, bp.title, bp.slug, bp.excerpt, bp.featured_image_url, bp.status, bp.view_count, bp.like_count, bp.comment_count, bp.published_at, bp.created_at, bp.updated_at, u.full_name AS author_name, u.profile_picture_url AS author_avatar, STRING_AGG(DISTINCT bc2.name, ', ') AS categories, STRING_AGG(DISTINCT bt.name, ', ') AS tags FROM blog_posts bp INNER JOIN blog_post_categories bpc ON bp.id = bpc.blog_post_id INNER JOIN blog_categories bc ON bpc.category_id = bc.id LEFT JOIN users u ON bp.user_id = u.id LEFT JOIN blog_post_categories bpc2 ON bp.id = bpc2.blog_post_id LEFT JOIN blog_categories bc2 ON bpc2.category_id = bc2.id LEFT JOIN blog_post_tags bpt ON bp.id = bpt.blog_post_id LEFT JOIN blog_tags bt ON bpt.tag_id = bt.id WHERE bp.status = 'PUBLISHED' AND bc.slug = #{categorySlug} GROUP BY bp.id, u.full_name, u.profile_picture_url ORDER BY
bp.title bp.created_at
${sortType} LIMIT #{limit} OFFSET #{offset}

SELECT bp.id, bp.title, bp.slug, bp.excerpt, bp.featured_image_url, bp.status, bp.view_count, bp.like_count, bp.comment_count, bp.published_at, bp.created_at, bp.updated_at, u.full_name AS author_name, u.profile_picture_url AS author_avatar, STRING_AGG(DISTINCT bc.name, ', ') AS categories, STRING_AGG(DISTINCT bt2.name, ', ') AS tags FROM blog_posts bp INNER JOIN blog_post_tags bpt ON bp.id = bpt.blog_post_id INNER JOIN blog_tags bt ON bpt.tag_id = bt.id LEFT JOIN users u ON bp.user_id = u.id LEFT JOIN blog_post_categories bpc ON bp.id = bpc.blog_post_id LEFT JOIN blog_categories bc ON bpc.category_id = bc.id LEFT JOIN blog_post_tags bpt2 ON bp.id = bpt2.blog_post_id LEFT JOIN blog_tags bt2 ON bpt2.tag_id = bt2.id WHERE bp.status = 'PUBLISHED' AND bt.slug = #{tagSlug} GROUP BY bp.id, u.full_name, u.profile_picture_url ORDER BY
bp.title bp.created_at
${sortType} LIMIT #{limit} OFFSET #{offset}

SELECT bp.id, bp.title, bp.slug, bp.excerpt, bp.featured_image_url, bp.status, bp.view_count, bp.like_count, bp.comment_count, bp.published_at, bp.created_at, bp.updated_at, u.full_name AS author_name, u.profile_picture_url AS author_avatar, STRING_AGG(DISTINCT bc.name, ', ') AS categories, STRING_AGG(DISTINCT bt.name, ', ') AS tags FROM blog_posts bp LEFT JOIN users u ON bp.user_id = u.id LEFT JOIN blog_post_categories bpc ON bp.id = bpc.blog_post_id LEFT JOIN blog_categories bc ON bpc.category_id = bc.id LEFT JOIN blog_post_tags bpt ON bp.id = bpt.blog_post_id LEFT JOIN blog_tags bt ON bpt.tag_id = bt.id
bp.user_id = #{authorId} AND bp.status = #{status}
GROUP BY bp.id, u.full_name, u.profile_picture_url ORDER BY
bp.title bp.created_at
${sortType} LIMIT #{limit} OFFSET #{offset}

SELECT bp.id, bp.title, bp.slug, bp.excerpt, bp.featured_image_url, bp.status, bp.view_count, bp.like_count, bp.comment_count, bp.published_at, bp.created_at, bp.updated_at, u.full_name AS author_name, u.profile_picture_url AS author_avatar, STRING_AGG(DISTINCT bc.name, ', ') AS categories, STRING_AGG(DISTINCT bt.name, ', ') AS tags FROM blog_posts bp LEFT JOIN users u ON bp.user_id = u.id LEFT JOIN blog_post_categories bpc ON bp.id = bpc.blog_post_id LEFT JOIN blog_categories bc ON bpc.category_id = bc.id LEFT JOIN blog_post_tags bpt ON bp.id = bpt.blog_post_id LEFT JOIN blog_tags bt ON bpt.tag_id = bt.id
bp.status = 'PUBLISHED' AND (bp.title ILIKE '%' || #{query} || '%' OR bp.content ILIKE '%' || #{query} || '%' OR bp.excerpt ILIKE '%' || #{query} || '%') AND bc.slug = #{category} AND bt.slug = #{tag}
GROUP BY bp.id, u.full_name, u.profile_picture_url ORDER BY
bp.title bp.created_at
${sortType} LIMIT #{limit} OFFSET #{offset}
